#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d", &N, &M);
        char grid[12][12]; // N,M ≤ 10
        for(int i=0;i<N;i++){
            scanf("%s", grid[i]);
        }
        int flips0=0, flips1=0;
        for(int i=0;i<N;i++){
            for(int j=0;j<M;j++){
                int even = ((i+j)&1)==0; // 0‑based indices, parity same as 1‑based
                if(even){
                    if(grid[i][j]=='.') flips0++; // should be land
                    if(grid[i][j]=='*') flips1++; // should be water for colour1
                }else{
                    if(grid[i][j]=='*') flips0++; // should be water
                    if(grid[i][j]=='.') flips1++; // should be land
                }
            }
        }
        int total = N*M;
        int ans;
        if(total%2==0){
            ans = flips0 < flips1 ? flips0 : flips1;
        }else{
            // when total is odd, the colour with more cells is the even colour (i+j even)
            ans = flips0;
        }
        printf("%d\n", ans);
    }
    return 0;
}

