import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            char[][] g = new char[N][M];
            for (int i = 0; i < N; i++) {
                String line = br.readLine();
                g[i] = line.toCharArray();
            }
            int flips0 = 0, flips1 = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    boolean even = ((i + j) & 1) == 0; // 0‑based parity
                    if (even) {
                        if (g[i][j] == '.') flips0++; // should be land
                        if (g[i][j] == '*') flips1++; // should be water for colour1
                    } else {
                        if (g[i][j] == '*') flips0++; // should be water
                        if (g[i][j] == '.') flips1++; // should be land for colour1
                    }
                }
            }
            int total = N * M;
            int ans = (total % 2 == 0) ? Math.min(flips0, flips1) : flips0;
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

