import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        grid = [list(next(it).strip()) for _ in range(N)]
        flips0 = flips1 = 0
        for i in range(N):
            for j in range(M):
                even = ((i + j) & 1) == 0
                if even:
                    if grid[i][j] == '.':
                        flips0 += 1
                    else:  # '*'
                        flips1 += 1
                else:
                    if grid[i][j] == '*':
                        flips0 += 1
                    else:
                        flips1 += 1
        total = N * M
        ans = min(flips0, flips1) if total % 2 == 0 else flips0
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

